import React, { useState, useEffect, useRef } from 'react';
import { ChevronLeft, ChevronRight } from 'lucide-react';
import './AboutUsPage.css';

const campusSlides = {
  depok: [
    { src: '/facilities/depok1.jpg', title: 'Depok Lab 1' },
    { src: '/facilities/depok2.jpg', title: 'Depok Lab 2' },
    { src: '/facilities/depok3.jpg', title: 'Depok Lab 3' },
  ],
  kalimalang: [
    { src: '/facilities/j1.jpg', title: 'Kalimalang Lab 1' },
    { src: '/facilities/j2.jpg', title: 'Kalimalang Lab 2' },
  ],
  karawaci: [
    { src: '/facilities/k1.jpg', title: 'Karawaci Lab 1' },
    { src: '/facilities/k2.jpg', title: 'Karawaci Lab 2' },
  ],
};

function FacilitySlider({ slides }) {
  const [current, setCurrent] = useState(0);
  const autoRef = useRef(null);

  useEffect(() => {
    setCurrent(0);
    clearInterval(autoRef.current);

    autoRef.current = setInterval(() => {
      setCurrent(prev => (prev + 1) % slides.length);
    }, 4000);

    return () => clearInterval(autoRef.current);
  }, [slides]);

  const next = () => setCurrent((current + 1) % slides.length);
  const prev = () => setCurrent((current - 1 + slides.length) % slides.length);

  return (
    <div className="facility-slider">
      <div className="facility-slider-main">
        <div
          className="facility-slider-track"
          style={{ transform: `translateX(-${current * 100}%)` }}
        >
          {slides.map((slide, i) => (
            <div key={i} className="facility-slide">
              <img src={slide.src} alt={slide.title} />
              <div className="facility-slide-overlay">
                <h4>{slide.title}</h4>
              </div>
            </div>
          ))}
        </div>

        {/* Navigation */}
        <button className="facility-btn facility-btn-prev" onClick={prev}>
          <ChevronLeft size={20} />
        </button>
        <button className="facility-btn facility-btn-next" onClick={next}>
          <ChevronRight size={20} />
        </button>

        {/* Dots */}
        <div className="facility-dots">
          {slides.map((_, i) => (
            <span
              key={i}
              className={`facility-dot ${i === current ? 'active' : ''}`}
            />
          ))}
        </div>
      </div>
    </div>
  );
}

export default function AboutUsPage() {
  const [activeCampus, setActiveCampus] = useState('depok');

  return (
    <section className="aboutus-section">
      <div className="container">

        <h2 className="section-title">Fasilitas</h2>

        {/* BUTTON CAMPUS */}
        <div className="campus-buttons">
          <button
            className={activeCampus === 'depok' ? 'active' : ''}
            onClick={() => setActiveCampus('depok')}
          >
            Kampus Depok (D)
          </button>
          <button
            className={activeCampus === 'kalimalang' ? 'active' : ''}
            onClick={() => setActiveCampus('kalimalang')}
          >
            Kampus Kalimalang (J)
          </button>
          <button
            className={activeCampus === 'karawaci' ? 'active' : ''}
            onClick={() => setActiveCampus('karawaci')}
          >
            Kampus Karawaci (K)
          </button>
        </div>

        {/* SLIDER */}
        <FacilitySlider slides={campusSlides[activeCampus]} />

        {/* TEAM */}
        <div className="team-section">
          <h2 className="section-title">Our Team</h2>

          <div className="team-hierarchy">
            <div className="team-card main">
              <h3>Director</h3>
            </div>

            <div className="team-row">
              <div className="team-card">Research Engineer</div>
              <div className="team-card">RnD Lab Technician</div>
              <div className="team-card">Practice Lab Technician</div>
              <div className="team-card">Assistant</div>
            </div>
          </div>
        </div>

      </div>
    </section>
  );
}
